  5→//! Column table formatting for JJK output
  6→//!
  7→//! Provides structured column layout to eliminate magic numbers/strings
  8→//! from formatted output operations. Single source of truth for headers,
  9→//! widths, and alignment.
 10→
 11→/// Gap between columns
 12→pub const JJRP_COLUMN_GAP: usize = 2;
 13→
 14→/// Minimum column width
 15→pub const JJRP_MIN_WIDTH: usize = 5;
 16→
 17→/// Column alignment
 18→#[derive(Debug, Clone, Copy, PartialEq, Eq)]
 19→pub enum jjrp_Align {
 20→    Left,
 21→    Right,
 22→}
 23→
 24→/// Column definition
 25→#[derive(Debug, Clone)]
 26→pub struct jjrp_Column {
 27→    /// Header text (single source of truth)
 28→    pub header: &'static str,
 29→    /// Minimum width (defaults to header.len())
 30→    pub min_width: usize,
 31→    /// Alignment
 32→    pub align: jjrp_Align,
 33→}
 34→
 35→impl jjrp_Column {
 36→    /// Create a new column with default min_width from header
 37→    pub fn new(header: &'static str, align: jjrp_Align) -> Self {
 38→        Self {
 39→            header,
 40→            min_width: header.len().max(JJRP_MIN_WIDTH),
 41→            align,
 42→        }
 43→    }
 44→
 45→    /// Create a new column with explicit min_width
 46→    pub fn with_width(header: &'static str, min_width: usize, align: jjrp_Align) -> Self {
 47→        Self {
 48→            header,
 49→            min_width: min_width.max(JJRP_MIN_WIDTH),
 50→            align,
 51→        }
 52→    }
 53→}
 54→
 55→/// Table with columns and computed widths
 56→pub struct jjrp_Table {
 57→    columns: Vec<jjrp_Column>,
 58→    widths: Vec<usize>,
 59→}
 60→
 61→impl jjrp_Table {
 62→    /// Create a new table with the given columns
 63→    pub fn jjrp_new(columns: Vec<jjrp_Column>) -> Self {
 64→        let widths = columns.iter().map(|c| c.min_width).collect();
 65→        Self { columns, widths }
 66→    }
 67→
 68→    /// Update column widths based on a data row
 69→    pub fn jjrp_measure(&mut self, row: &[&str]) {
 70→        for (i, value) in row.iter().enumerate() {
 71→            if i < self.widths.len() {
 72→                self.widths[i] = self.widths[i].max(value.len());
 73→            }
 74→        }
 75→    }
 76→
 77→    /// Write the header row to a buffer
 78→    pub fn jjrp_write_header(&self, buf: &mut String) {
 79→        use std::fmt::Write;
 80→        let mut parts = Vec::new();
 81→        for (i, col) in self.columns.iter().enumerate() {
 82→            let width = self.widths[i];
 83→            let formatted = match col.align {
 84→                jjrp_Align::Left => format!("{:<width$}", col.header, width = width),
 85→                jjrp_Align::Right => format!("{:>width$}", col.header, width = width),
 86→            };
 87→            parts.push(formatted);
 88→        }
 89→        let _ = writeln!(buf, "{}", parts.join(&" ".repeat(JJRP_COLUMN_GAP)));
 90→    }
 91→
 92→    /// Write a separator line to a buffer
 93→    /// Uses box drawing character to avoid markdown interpretation of dashes
 94→    pub fn jjrp_write_separator(&self, buf: &mut String) {
 95→        use std::fmt::Write;
 96→        let mut parts = Vec::new();
 97→        for width in &self.widths {
 98→            parts.push("─".repeat(*width));
 99→        }
100→        let _ = writeln!(buf, "{}", parts.join(&" ".repeat(JJRP_COLUMN_GAP)));
101→    }
102→
103→    /// Write a data row to a buffer
104→    pub fn jjrp_write_row(&self, buf: &mut String, values: &[&str]) {
105→        use std::fmt::Write;
106→        let mut parts = Vec::new();
107→        for (i, value) in values.iter().enumerate() {
108→            if i < self.columns.len() {
109→                let width = self.widths[i];
110→                let col = &self.columns[i];
111→                let formatted = match col.align {
112→                    jjrp_Align::Left => format!("{:<width$}", value, width = width),
113→                    jjrp_Align::Right => format!("{:>width$}", value, width = width),
114→                };
115→                parts.push(formatted);
116→            }
117→        }
118→        let _ = writeln!(buf, "{}", parts.join(&" ".repeat(JJRP_COLUMN_GAP)));
119→    }
120→}
121→
122→#[cfg(test)]
123→mod tests {
124→    use super::*;
125→
126→    #[test]
127→    fn test_column_new() {
128→        let col = jjrp_Column::new("Test", jjrp_Align::Left);
129→        assert_eq!(col.header, "Test");
130→        assert_eq!(col.min_width, JJRP_MIN_WIDTH);
131→        assert_eq!(col.align, jjrp_Align::Left);
132→    }
133→
134→    #[test]
135→    fn test_column_with_width() {
136→        let col = jjrp_Column::with_width("ID", 10, jjrp_Align::Right);
137→        assert_eq!(col.header, "ID");
138→        assert_eq!(col.min_width, 10);
139→        assert_eq!(col.align, jjrp_Align::Right);
140→    }
141→
142→    #[test]
143→    fn test_table_measure() {
144→        let columns = vec![
145→            jjrp_Column::new("Name", jjrp_Align::Left),
146→            jjrp_Column::new("ID", jjrp_Align::Right),
147→        ];
148→        let mut table = jjrp_Table::jjrp_new(columns);
149→
150→        // Initial widths are min_width
151→        assert_eq!(table.widths[0], JJRP_MIN_WIDTH);
152→        assert_eq!(table.widths[1], JJRP_MIN_WIDTH);
153→
154→        // Measure a row with longer values
155→        table.jjrp_measure(&["Very Long Name", "12345"]);
156→        assert_eq!(table.widths[0], 14); // "Very Long Name".len()
157→        assert_eq!(table.widths[1], JJRP_MIN_WIDTH); // Still min because "12345" is shorter
158→    }
159→
160→    #[test]
161→    fn test_table_output() {
162→        let columns = vec![
163→            jjrp_Column::new("₣Fire", jjrp_Align::Left),
164→            jjrp_Column::new("Silks", jjrp_Align::Left),
165→            jjrp_Column::new("Count", jjrp_Align::Right),
166→        ];
167→        let mut table = jjrp_Table::jjrp_new(columns);
168→
169→        // Measure some data
170→        table.jjrp_measure(&["₣AB", "test-heat", "42"]);
171→        table.jjrp_measure(&["₣CD", "another-heat-name", "100"]);
172→
173→        // Write to buffer and verify they don't panic
174→        let mut buf = String::new();
175→        table.jjrp_write_header(&mut buf);
176→        table.jjrp_write_separator(&mut buf);
177→        table.jjrp_write_row(&mut buf, &["₣AB", "test-heat", "42"]);
178→        table.jjrp_write_row(&mut buf, &["₣CD", "another-heat-name", "100"]);
179→        assert!(!buf.is_empty());
180→    }
181→}
