 50→// ============================================================================
 51→// Result conversion
 52→// ============================================================================
 53→
 54→/// Convert handler (exit_code, output) to MCP CallToolResult.
 55→fn jjrm_result(result: (i32, String)) -> Result<CallToolResult, McpError> {
 56→    let (code, output) = result;
 57→    if code == 0 {
 58→        Ok(CallToolResult::success(vec![Content::text(output)]))
 59→    } else {
 60→        Ok(CallToolResult::error(vec![Content::text(output)]))
 61→    }
 62→}
 63→
 64→/// Return deserialization error as MCP error result.
 65→fn jjrm_deser_error(cmd: &str, e: serde_json::Error) -> Result<CallToolResult, McpError> {
 66→    Ok(CallToolResult::error(vec![Content::text(format!("jjx {}: invalid params: {}", cmd, e))]))
 67→}
