255→#[derive(Debug, serde::Deserialize, schemars::JsonSchema)]
256→pub struct jjrm_JjxParams {
257→    #[schemars(description = "Command name: jjx_list, jjx_show, jjx_orient, jjx_record, jjx_mark, jjx_log, jjx_validate, jjx_create, jjx_enroll, jjx_close, jjx_archive, jjx_reorder, jjx_revise_docket, jjx_arm, jjx_relabel, jjx_drop, jjx_relocate, jjx_alter, jjx_search, jjx_get_brief, jjx_get_coronets, jjx_paddock, jjx_continue, jjx_transfer, jjx_landing")]
258→    pub command: String,
259→    #[schemars(description = "Command parameters as JSON object. See CLAUDE.md for per-command schemas.")]
260→    #[serde(default = "jjrm_empty_object")]
261→    pub params: serde_json::Value,
262→}
