11→use std::path::PathBuf;
12→use chrono::Local;
13→
14→/// Write formatted text to a buf String, suppressing the Result.
15→/// Replaces `eprintln!` in command handlers so errors flow through MCP transport
16→/// instead of vanishing into stderr.
17→#[macro_export]
18→macro_rules! jjbuf {
19→    ($buf:expr, $($arg:tt)*) => {
20→        { use std::fmt::Write; let _ = writeln!($buf, $($arg)*); }
21→    };
22→}
23→
24→/// Default path to the Gallops JSON file
25→pub const JJRC_DEFAULT_GALLOPS_PATH: &str = ".claude/jjm/jjg_gallops.json";
26→
27→/// Get the default Gallops file path relative to repo root
28→pub fn jjrc_default_gallops_path() -> PathBuf {
29→    PathBuf::from(JJRC_DEFAULT_GALLOPS_PATH)
30→}
31→
32→/// Generate timestamp in YYMMDD format
33→pub fn jjrc_timestamp_date() -> String {
34→    Local::now().format("%y%m%d").to_string()
35→}
36→
37→/// Generate timestamp in YYMMDD-HHMM format
38→pub fn jjrc_timestamp_full() -> String {
39→    Local::now().format("%y%m%d-%H%M").to_string()
40→}
41→
42→/// Get creation date from BURD_NOW_STAMP env var, or fall back to system clock
43→///
44→/// If BURD_NOW_STAMP is set (format: YYYYMMDD-HHMMSS-PID-RANDOM),
45→/// extract YYYYMMDD and convert to YYMMDD (drop century).
46→/// Otherwise, use jjrc_timestamp_date() for current system clock.
47→pub fn jjrc_timestamp_from_env() -> String {
48→    match std::env::var("BURD_NOW_STAMP") {
49→        Ok(stamp) => {
50→            // Expected format: YYYYMMDD-HHMMSS-PID-RANDOM
51→            // Extract YYYYMMDD and convert to YYMMDD by dropping first 2 digits
52→            if stamp.len() >= 8 {
53→                let yyyymmdd = &stamp[..8];
54→                // Drop century (first 2 chars) to get YYMMDD
55→                if let Ok(year) = yyyymmdd[..4].parse::<u32>() {
56→                    let yy = year % 100;
57→                    let mmdd = &yyyymmdd[4..];
58→                    return format!("{:02}{}", yy, mmdd);
59→                }
60→            }
61→            // Fall back to system clock if parsing fails
62→            jjrc_timestamp_date()
63→        }
64→        Err(_) => {
65→            // BURD_NOW_STAMP not set, use system clock
66→            jjrc_timestamp_date()
67→        }
68→    }
69→}
