  5→//! VVC Machine Commit - programmatic commit infrastructure
  6→//!
  7→//! For automated operations that know exactly what files to commit
  8→//! and don't need Claude assistance. Contrast with vvcc_commit which
  9→//! is designed for interactive sessions with Claude message generation.
 10→//!
 11→//! Use cases:
 12→//!   - JJK retire: trophy file + paddock + gallops update
 13→//!   - VOK install: kit files being installed
 14→//!   - CMK normalize: normalized concept model files
 15→//!   - Any automated operation with predictable file sets
 16→//!
 17→//! Exit codes (when using vvcm_run):
 18→//!   0 - Success (commit hash printed to stdout)
 19→//!   1 - Failure (staging failed, guard failed, commit failed)
 20→
 21→use crate::vvcc_commit::vvcc_CommitLock;
 22→use crate::vvcg_guard;
 23→
 24→/// Arguments for machine commit operation
 25→#[derive(Debug, Clone)]
 26→pub struct vvcm_CommitArgs {
 27→    /// Explicit files to stage (required, non-empty)
 28→    pub files: Vec<String>,
 29→    /// Commit message (required)
 30→    pub message: String,
 31→    /// Size limit in bytes for guard check
 32→    pub size_limit: u64,
 33→    /// Warning threshold in bytes for guard check
 34→    pub warn_limit: u64,
 35→}
 36→
 37→/// Machine commit for programmatic operations.
 38→///
 39→/// Unlike vvcc_commit, this:
 40→/// - Stages only specified files (not git add -A)
 41→/// - Requires explicit message (no Claude generation)
 42→/// - Does not add Co-Authored-By trailer
 43→/// - Uses caller-specified guard limits
 44→///
 45→/// The `_lock` parameter serves as compile-time proof that the caller
 46→/// holds the commit lock. The lock is not consumed; caller retains it.
 47→///
 48→/// Returns the commit hash on success.
 49→pub fn vvcm_commit(
 50→    _lock: &vvcc_CommitLock,
 51→    args: &vvcm_CommitArgs,
 52→) -> Result<String, String> {
 53→    // Validate args
 54→    if args.files.is_empty() {
 55→        return Err("files list must not be empty".to_string());
 56→    }
 57→    if args.message.is_empty() {
 58→        return Err("message must not be empty".to_string());
 59→    }
 60→
 61→    // Stage explicit files
 62→    zvvcm_stage_files(&args.files)?;
 63→
 64→    // Run guard with custom limits
 65→    let guard_args = vvcg_guard::vvcg_GuardArgs {
 66→        limit: args.size_limit,
 67→        warn: args.warn_limit,
 68→    };
 69→    let guard_result = vvcg_guard::vvcg_run(&guard_args, None);
 70→    match guard_result {
 71→        0 => {}
 72→        1 => return Err("Staged content exceeds size limit".to_string()),
 73→        2 => {
 74→            eprintln!("vvcm_commit: WARNING - staged content near size limit");
 75→        }
 76→        _ => return Err(format!("Guard returned unexpected code: {}", guard_result)),
 77→    }
 78→
 79→    // Commit with message (no Co-Authored-By)
 80→    zvvcm_execute_commit(&args.message)
 81→}
