 83→/// Stage specific files using git add
 84→fn zvvcm_stage_files(files: &[String]) -> Result<(), String> {
 85→    let mut cmd = crate::vvce_git_command(&["add", "--"]);
 86→    for file in files {
 87→        cmd.arg(file);
 88→    }
 89→
 90→    let result = cmd
 91→        .output()
 92→        .map_err(|e| format!("Failed to run git add: {}", e))?;
 93→
 94→    if result.status.success() {
 95→        Ok(())
 96→    } else {
 97→        Err(format!(
 98→            "git add failed: {}",
 99→            String::from_utf8_lossy(&result.stderr)
100→        ))
101→    }
102→}
103→
104→/// Execute git commit with message (no Co-Authored-By)
105→fn zvvcm_execute_commit(message: &str) -> Result<String, String> {
106→    let output = crate::vvce_git_command(&["commit", "-m", message])
107→        .output()
108→        .map_err(|e| format!("Failed to run git commit: {}", e))?;
109→
110→    if !output.status.success() {
111→        let stderr = String::from_utf8_lossy(&output.stderr);
112→        return Err(format!("git commit failed: {}", stderr));
113→    }
114→
115→    // Get commit hash
116→    let hash_output = crate::vvce_git_command(&["rev-parse", "HEAD"])
117→        .output()
118→        .map_err(|e| format!("Failed to get commit hash: {}", e))?;
119→
120→    if !hash_output.status.success() {
121→        return Err("Failed to retrieve commit hash".to_string());
122→    }
123→
124→    let hash = String::from_utf8_lossy(&hash_output.stdout)
125→        .trim()
126→        .to_string();
127→
128→    Ok(hash)
129→}
