105→/// Change status for a staged file
106→#[derive(Debug, Clone, Copy, PartialEq)]
107→enum zvvcg_ChangeStatus {
108→    Added,
109→    Modified,
110→    Deleted,
111→}
112→
113→/// Get the change status of a staged file (A/M/D)
114→fn zvvcg_get_change_status(path: &str, repo_dir: Option<&Path>) -> Result<zvvcg_ChangeStatus, String> {
115→    let mut cmd = crate::vvce_git_command(&["diff", "--cached", "--name-status", "--", path]);
116→    if let Some(dir) = repo_dir {
117→        cmd.current_dir(dir);
118→    }
119→    let output = cmd
120→        .output()
121→        .map_err(|e| format!("Failed to run git diff --name-status for {}: {}", path, e))?;
122→
123→    if !output.status.success() {
124→        return Err(format!("git diff --cached --name-status -- {} failed", path));
125→    }
126→
127→    let stdout = String::from_utf8_lossy(&output.stdout);
128→    let line = stdout.trim();
129→
130→    if line.is_empty() {
131→        // File not in diff - shouldn't happen if called from staged files list
132→        return Err(format!("File {} not found in staged changes", path));
133→    }
134→
135→    // Format: "A\tpath" or "M\tpath" or "D\tpath" (or R/C with rename info)
136→    let status_char = line.chars().next().unwrap_or('?');
137→
138→    match status_char {
139→        'A' => Ok(zvvcg_ChangeStatus::Added),
140→        'M' => Ok(zvvcg_ChangeStatus::Modified),
141→        'D' => Ok(zvvcg_ChangeStatus::Deleted),
142→        'R' | 'C' => Ok(zvvcg_ChangeStatus::Modified), // Rename/Copy treated as modified
143→        _ => Err(format!("Unknown status '{}' for {}", status_char, path)),
144→    }
145→}
146→
147→/// Check if a modified file is binary
148→///
149→/// Uses git diff --numstat which reports `-\t-\t<path>` for binary files.
150→fn zvvcg_is_binary(path: &str, repo_dir: Option<&Path>) -> Result<bool, String> {
151→    let mut cmd = crate::vvce_git_command(&["diff", "--cached", "--numstat", "--", path]);
152→    if let Some(dir) = repo_dir {
153→        cmd.current_dir(dir);
154→    }
155→    let output = cmd
156→        .output()
157→        .map_err(|e| format!("Failed to run git diff --numstat for {}: {}", path, e))?;
158→
159→    if !output.status.success() {
160→        return Err(format!("git diff --cached --numstat -- {} failed", path));
161→    }
162→
163→    let stdout = String::from_utf8_lossy(&output.stdout);
164→    let line = stdout.trim();
165→
166→    // Binary files show: "-\t-\t<path>"
167→    // Text files show: "<added>\t<removed>\t<path>"
168→    Ok(line.starts_with("-\t-\t"))
169→}
170→
171→/// Get the blob size for a staged file
172→fn zvvcg_get_blob_size(path: &str, repo_dir: Option<&Path>) -> Result<u64, String> {
173→    // Get staged blob info: mode, sha, stage, path
174→    let mut cmd = crate::vvce_git_command(&["ls-files", "--cached", "-s", "--", path]);
175→    if let Some(dir) = repo_dir {
176→        cmd.current_dir(dir);
177→    }
178→    let output = cmd
179→        .output()
180→        .map_err(|e| format!("Failed to run git ls-files for {}: {}", path, e))?;
181→
182→    if !output.status.success() {
183→        return Err(format!("git ls-files --cached -s -- {} failed", path));
184→    }
185→
186→    let stdout = String::from_utf8_lossy(&output.stdout);
187→    let line = stdout.trim();
188→
189→    if line.is_empty() {
190→        return Ok(0);
191→    }
192→
193→    // Parse: "100644 <sha> 0\t<path>"
194→    let parts: Vec<&str> = line.split_whitespace().collect();
195→    if parts.len() < 2 {
196→        return Err(format!("Unexpected git ls-files output for {}: {}", path, line));
197→    }
198→
199→    let blob_sha = parts[1];
200→
201→    // Get actual blob size
202→    let mut cmd = crate::vvce_git_command(&["cat-file", "-s", blob_sha]);
203→    if let Some(dir) = repo_dir {
204→        cmd.current_dir(dir);
205→    }
206→    let output = cmd
207→        .output()
208→        .map_err(|e| format!("Failed to run git cat-file for {}: {}", blob_sha, e))?;
209→
210→    if !output.status.success() {
211→        return Err(format!("git cat-file -s {} failed", blob_sha));
212→    }
213→
214→    let size_str = String::from_utf8_lossy(&output.stdout);
215→    size_str
216→        .trim()
217→        .parse::<u64>()
218→        .map_err(|e| format!("Failed to parse blob size for {}: {}", path, e))
219→}
