221→/// Get the diff output size for a modified text file
222→fn zvvcg_get_text_diff_size(path: &str, repo_dir: Option<&Path>) -> Result<u64, String> {
223→    let mut cmd = crate::vvce_git_command(&["diff", "--cached", "--", path]);
224→    if let Some(dir) = repo_dir {
225→        cmd.current_dir(dir);
226→    }
227→    let output = cmd
228→        .output()
229→        .map_err(|e| format!("Failed to run git diff for {}: {}", path, e))?;
230→
231→    if !output.status.success() {
232→        return Err(format!("git diff --cached -- {} failed", path));
233→    }
234→
235→    Ok(output.stdout.len() as u64)
236→}
