238→/// Get incremental storage cost for a staged file
239→///
240→/// Implements the cost model from the module doc:
241→/// - New file (A): blob size
242→/// - Modified text (M): diff size
243→/// - Modified binary (M): blob size
244→/// - Deleted file (D): 0
245→///
246→/// Public for testing. External callers should use vvcg_run.
247→pub(crate) fn zvvcg_get_diff_size(path: &str, repo_dir: Option<&Path>) -> Result<u64, String> {
248→    let status = zvvcg_get_change_status(path, repo_dir)?;
249→
250→    match status {
251→        zvvcg_ChangeStatus::Deleted => Ok(0),
252→        zvvcg_ChangeStatus::Added => zvvcg_get_blob_size(path, repo_dir),
253→        zvvcg_ChangeStatus::Modified => {
254→            if zvvcg_is_binary(path, repo_dir)? {
255→                zvvcg_get_blob_size(path, repo_dir)
256→            } else {
257→                zvvcg_get_text_diff_size(path, repo_dir)
258→            }
259→        }
260→    }
261→}
