263→/// Run the guard check on staged content.
264→///
265→/// `repo_dir`: Optional path to git repository. If None, uses current working directory.
266→///
267→/// Returns:
268→/// - 0: Under limit (OK)
269→/// - 1: Over limit (BLOCKED)
270→/// - 2: Over warn threshold (WARNING)
271→pub fn vvcg_run(args: &vvcg_GuardArgs, repo_dir: Option<&Path>) -> i32 {
272→    let files = match zvvcg_get_staged_files(repo_dir) {
273→        Ok(f) => f,
274→        Err(e) => {
275→            eprintln!("guard: error: {}", e);
276→            return 1;
277→        }
278→    };
279→
280→    let total_size: u64 = files.iter().map(|f| f.size).sum();
281→
282→    if total_size > args.limit {
283→        eprintln!(
284→            "guard: BLOCKED - staged content {} bytes exceeds limit {} bytes",
285→            total_size, args.limit
286→        );
287→        eprintln!();
288→        eprintln!("Breakdown by file:");
289→        let mut sorted_files = files;
290→        sorted_files.sort_by(|a, b| b.size.cmp(&a.size));
291→        for f in sorted_files.iter().take(10) {
292→            eprintln!("  {:>10} bytes  {}", f.size, f.path);
293→        }
294→        if sorted_files.len() > 10 {
295→            eprintln!("  ... and {} more files", sorted_files.len() - 10);
296→        }
297→        return 1;
298→    }
299→
300→    if total_size > args.warn {
301→        eprintln!(
302→            "guard: WARNING - staged content {} bytes exceeds warning threshold {} bytes",
303→            total_size, args.warn
304→        );
305→        return 2;
306→    }
307→
308→    0
309→}
