187→/// Generate commit message using claude CLI
188→fn zvvcc_generate_message_with_claude(diff: &str) -> Result<String, String> {
189→    let prompt = format!(
190→        "Generate a concise commit message for this diff:\n\n<diff>\n{}\n</diff>\n\nRespond with only the commit message, no explanation.",
191→        diff
192→    );
193→
194→    let output = crate::vvce_claude_command()
195→        .args([
196→            "--print",
197→            "--system-prompt",
198→            "Output only a conventional git commit message. No explanation or commentary. Do not wrap in markdown code blocks.",
199→            "--model",
200→            "haiku",
201→            "--no-session-persistence",
202→            &prompt,
203→        ])
204→        .output()
205→        .map_err(|e| format!("Failed to invoke claude: {}", e))?;
206→
207→    if !output.status.success() {
208→        let stderr = String::from_utf8_lossy(&output.stderr);
209→        return Err(format!("claude --print failed: {}", stderr));
210→    }
211→
212→    let message = String::from_utf8_lossy(&output.stdout).trim().to_string();
213→
214→    // Strip markdown code blocks if Claude wrapped the response
215→    let message = if message.starts_with("```") {
216→        let after_opening = message.find('\n').map(|i| i + 1).unwrap_or(0);
217→        let before_closing = message.rfind("```").unwrap_or(message.len());
218→        if before_closing > after_opening {
219→            message[after_opening..before_closing].trim().to_string()
220→        } else {
221→            message
222→        }
223→    } else {
224→        message
225→    };
226→
227→    // Strip Co-Authored-By trailer if Claude CLI added it from global settings
228→    let message: String = message
229→        .lines()
230→        .filter(|line| !line.starts_with("Co-Authored-By:"))
231→        .collect::<Vec<_>>()
232→        .join("\n")
233→        .trim()
234→        .to_string();
235→
236→    if message.is_empty() {
237→        return Err("claude returned empty message".to_string());
238→    }
239→
240→    Ok(message)
241→}
