243→/// Format the full commit message with prefix and co-author
244→fn zvvcc_format_commit_message(prefix: Option<&str>, message: &str) -> String {
245→    let mut full_message = String::new();
246→
247→    if let Some(p) = prefix {
248→        full_message.push_str(p);
249→    }
250→
251→    full_message.push_str(message);
252→
253→    full_message
