256→/// Execute the git commit
257→fn zvvcc_execute_commit(message: &str, allow_empty: bool) -> Result<String, String> {
258→    let mut args = vec!["commit", "-m", message];
259→
260→    if allow_empty {
261→        args.push("--allow-empty");
262→    }
263→
264→    let output = crate::vvce_git_command(&args)
265→        .output()
266→        .map_err(|e| format!("Failed to run git commit: {}", e))?;
267→
268→    if !output.status.success() {
269→        let stderr = String::from_utf8_lossy(&output.stderr);
270→        return Err(format!("git commit failed: {}", stderr));
271→    }
272→
273→    let hash_output = crate::vvce_git_command(&["rev-parse", "HEAD"])
274→        .output()
275→        .map_err(|e| format!("Failed to get commit hash: {}", e))?;
276→
277→    if !hash_output.status.success() {
278→        return Err("Failed to retrieve commit hash".to_string());
279→    }
280→
281→    Ok(String::from_utf8_lossy(&hash_output.stdout)
282→        .trim()
283→        .to_string())
284→}
