286→/// Run the commit workflow.
287→///
288→/// Returns exit code: 0 for success, 1 for failure.
289→/// On success, prints commit hash to stdout.
290→///
291→/// This is the simple API that acquires and releases the lock automatically.
292→/// For operations that need to hold the lock across multiple steps, use
293→/// `vvcc_CommitLock::vvcc_acquire()` instead.
294→pub fn vvcc_run(args: &vvcc_CommitArgs) -> i32 {
295→    let lock = match vvcc_CommitLock::vvcc_acquire() {
296→        Ok(l) => l,
297→        Err(e) => {
298→            eprintln!("commit: error: {}", e);
299→            return 1;
300→        }
301→    };
302→
303→    match lock.vvcc_commit(args) {
304→        Ok(hash) => {
305→            println!("{}", hash);
306→            0
307→        }
308→        Err(e) => {
309→            eprintln!("commit: error: {}", e);
310→            1
311→        }
312→    }
313→    // lock dropped here, releasing the git ref lock
314→}
315→
316→/// Inner workflow that can return Result for cleaner error handling
317→fn zvvcc_run_commit_workflow(args: &vvcc_CommitArgs) -> Result<String, String> {
318→    if !args.no_stage {
319→        zvvcc_stage_changes()?;
320→    }
321→
322→    if !args.allow_empty && !zvvcc_has_staged_changes()? {
323→        return Err("Nothing to commit".to_string());
324→    }
325→
326→    zvvcc_run_guard(args)?;
327→
328→    let message = match &args.message {
329→        Some(m) => m.clone(),
330→        None => {
331→            let diff = zvvcc_get_staged_diff()?;
332→            if diff.is_empty() && !args.allow_empty {
333→                return Err("No diff to generate message from".to_string());
334→            }
335→            zvvcc_generate_message_with_claude(&diff)?
336→        }
337→    };
338→
339→    let full_message = zvvcc_format_commit_message(args.prefix.as_deref(), &message);
340→
341→    zvvcc_execute_commit(&full_message, args.allow_empty)
342→}
