  5→//! VVC Environment - BUD environment validation and access
  6→//!
  7→//! Provides validated access to BUD environment variables that are
  8→//! guaranteed to be set when vvx is invoked via tabtarget.
  9→//!
 10→//! Validates on first access and panics if any required variable is missing.
 11→//! This is intentional fail-fast behavior - vvx should never run outside
 12→//! the BUK tabtarget context.
 13→
 14→use std::path::PathBuf;
 15→use std::sync::OnceLock;
 16→
 17→/// BUD environment - validated on first access
 18→pub struct VvcEnv {
 19→    /// Ephemeral temp directory for intermediate files (BURD_TEMP_DIR)
 20→    pub temp_dir: PathBuf,
 21→    /// Output directory for command results (BURD_OUTPUT_DIR)
 22→    pub output_dir: PathBuf,
 23→    /// Invocation identity timestamp-pid-random (BURD_NOW_STAMP)
 24→    pub now_stamp: String,
 25→    /// Git describe output for provenance (BURD_GIT_CONTEXT)
 26→    pub git_context: String,
 27→}
 28→
 29→/// Singleton storage for validated environment
 30→static ENV: OnceLock<VvcEnv> = OnceLock::new();
 31→
 32→/// Get validated BUD environment.
 33→///
 34→/// On first call, validates all required environment variables and caches
 35→/// the result. Panics if any required variable is missing or invalid.
 36→///
 37→/// Subsequent calls return the cached reference.
 38→///
 39→/// # Panics
 40→///
 41→/// Panics if any of these environment variables are missing:
 42→/// - `BURD_TEMP_DIR` - must be set and point to an existing directory
 43→/// - `BURD_OUTPUT_DIR` - must be set and point to an existing directory
 44→/// - `BURD_NOW_STAMP` - must be set (non-empty)
 45→/// - `BURD_GIT_CONTEXT` - must be set (non-empty)
 46→///
 47→/// This is intentional fail-fast behavior. vvx should only run via
 48→/// BUK tabtarget which guarantees these variables are set.
 49→pub fn vvce_env() -> &'static VvcEnv {
 50→    ENV.get_or_init(|| zvvce_validate_env())
 51→}
 52→
 53→/// Validate environment and construct VvcEnv, or panic with clear error
 54→fn zvvce_validate_env() -> VvcEnv {
 55→    let mut missing: Vec<&str> = Vec::new();
 56→    let mut invalid: Vec<String> = Vec::new();
 57→
 58→    // Validate BURD_TEMP_DIR (canonicalize to absolute path for test compatibility)
 59→    let temp_dir = match std::env::var("BURD_TEMP_DIR") {
 60→        Ok(v) if !v.is_empty() => {
 61→            let path = PathBuf::from(&v);
 62→            match path.canonicalize() {
 63→                Ok(abs_path) => {
 64→                    if !abs_path.is_dir() {
 65→                        invalid.push(format!("BURD_TEMP_DIR='{}' is not a directory", v));
 66→                    }
 67→                    abs_path
 68→                }
 69→                Err(e) => {
 70→                    invalid.push(format!("BURD_TEMP_DIR='{}' cannot be resolved: {}", v, e));
 71→                    path
 72→                }
 73→            }
 74→        }
 75→        Ok(_) => {
 76→            missing.push("BURD_TEMP_DIR");
 77→            PathBuf::new()
 78→        }
 79→        Err(_) => {
 80→            missing.push("BURD_TEMP_DIR");
 81→            PathBuf::new()
 82→        }
 83→    };
 84→
 85→    // Validate BURD_OUTPUT_DIR (canonicalize to absolute path for consistency)
 86→    let output_dir = match std::env::var("BURD_OUTPUT_DIR") {
 87→        Ok(v) if !v.is_empty() => {
 88→            let path = PathBuf::from(&v);
 89→            match path.canonicalize() {
 90→                Ok(abs_path) => {
 91→                    if !abs_path.is_dir() {
 92→                        invalid.push(format!("BURD_OUTPUT_DIR='{}' is not a directory", v));
 93→                    }
 94→                    abs_path
 95→                }
 96→                Err(e) => {
 97→                    invalid.push(format!("BURD_OUTPUT_DIR='{}' cannot be resolved: {}", v, e));
 98→                    path
 99→                }
100→            }
101→        }
102→        Ok(_) => {
103→            missing.push("BURD_OUTPUT_DIR");
104→            PathBuf::new()
105→        }
106→        Err(_) => {
107→            missing.push("BURD_OUTPUT_DIR");
108→            PathBuf::new()
109→        }
110→    };
111→
112→    // Validate BURD_NOW_STAMP
113→    let now_stamp = match std::env::var("BURD_NOW_STAMP") {
114→        Ok(v) if !v.is_empty() => v,
115→        _ => {
116→            missing.push("BURD_NOW_STAMP");
117→            String::new()
118→        }
119→    };
120→
121→    // Validate BURD_GIT_CONTEXT
122→    let git_context = match std::env::var("BURD_GIT_CONTEXT") {
123→        Ok(v) if !v.is_empty() => v,
124→        _ => {
125→            missing.push("BURD_GIT_CONTEXT");
126→            String::new()
127→        }
128→    };
129→
130→    // Report all errors at once
131→    if !missing.is_empty() || !invalid.is_empty() {
132→        let mut msg = String::from("vvx: BUD environment validation failed\n");
133→        msg.push_str("\nvvx must be invoked via BUK tabtarget (tt/vvw-r.RunVVX.sh)\n");
134→
135→        if !missing.is_empty() {
136→            msg.push_str("\nMissing environment variables:\n");
137→            for var in &missing {
138→                msg.push_str(&format!("  - {}\n", var));
139→            }
140→        }
141→
142→        if !invalid.is_empty() {
143→            msg.push_str("\nInvalid environment variables:\n");
144→            for err in &invalid {
145→                msg.push_str(&format!("  - {}\n", err));
146→            }
147→        }
148→
149→        panic!("{}", msg);
150→    }
151→
152→    VvcEnv {
153→        temp_dir,
154→        output_dir,
155→        now_stamp,
156→        git_context,
157→    }
158→}
