160→/// Create a Command for invoking git as a subprocess.
161→///
162→/// Disconnects stdin to prevent child process from inheriting the
163→/// MCP server's stdin fd, which causes transport deadlock.
164→pub fn vvce_git_command(args: &[&str]) -> std::process::Command {
165→    let mut cmd = std::process::Command::new("git");
166→    cmd.args(args);
167→    cmd.stdin(std::process::Stdio::null());
168→    cmd
169→}
170→
171→/// Create a Command for invoking claude as a subprocess.
172→///
173→/// Removes the CLAUDECODE environment variable to prevent the
174→/// nested-session guard (v2.1.39+) from blocking subprocess invocations
175→/// that are legitimate tool usage, not interactive nesting.
176→/// Disconnects stdin to prevent MCP transport deadlock.
177→pub fn vvce_claude_command() -> std::process::Command {
178→    let mut cmd = std::process::Command::new("claude");
179→    cmd.env_remove("CLAUDECODE");
180→    cmd.stdin(std::process::Stdio::null());
181→    cmd
182→}
